query:
{
  sqlDatabases(
    where: {
      AND: [
        { publicAccessBlocked: { eq: false } }
        {
          sqlServer: {
            firewallRules_SOME: {
              startIpAddress: { eq: "0.0.0.0" }
              endIpAddress: { eq: "255.255.255.255" }
            }
          }
        }
        { OR: [{ tlsStatus: { eq: "disabled" } }, { tlsMinimumVersion_LT: 1.2 }] }
      ]
    }
  ) {...AssetFragment tlsStatus tlsMinimumVersion}
}
